   110→}
   111→
   112→/// Holds all conversations plus an index for fast lookup.
   113→pub struct ConversationSet {
   114→    /// All reconstructed conversations.
   115→    pub conversations: Vec<Conversation>,
   116→    /// Maps event ID → conversation index for O(1) lookup.
   117→    event_index: HashMap<EventId, usize>,
   118→}
   119→
   120→impl ConversationSet {
   121→    /// Get conversation containing the given event.
   122→    pub fn for_event(&self, event_id: EventId) -> Option<&Conversation> {
   123→        self.event_index
   124→            .get(&event_id)
   125→            .map(|&idx| &self.conversations[idx])
   126→    }
   127→
   128→    /// Get all conversations, sorted by start time.
   129→    pub fn sorted_by_time(&self) -> Vec<&Conversation> {
   130→        let mut sorted: Vec<_> = self.conversations.iter().collect();
   131→        sorted.sort_by_key(|c| c.metrics.start_time);
   132→        sorted
   133→    }
   134→
   135→    /// Filter conversations by protocol.
   136→    pub fn by_protocol(&self, protocol: TransportKind) -> Vec<&Conversation> {
   137→        self.conversations
   138→            .iter()
   139→            .filter(|c| c.protocol == protocol)
   140→            .collect()
   141→    }
   142→
   143→    /// Summary statistics.
   144→    pub fn stats(&self) -> ConversationStats {
   145→        let mut by_protocol = HashMap::new();
   146→        let mut by_state = HashMap::new();
   147→        let mut by_kind = HashMap::new();
   148→
   149→        for conv in &self.conversations {
   150→            *by_protocol.entry(conv.protocol).or_insert(0) += 1;
   151→            *by_state.entry(conv.state).or_insert(0) += 1;
   152→            *by_kind.entry(conv.kind).or_insert(0) += 1;
   153→        }
   154→
   155→        ConversationStats {
   156→            total: self.conversations.len(),
   157→            by_protocol,
   158→            by_state,
   159→            by_kind,
   160→        }
   161→    }
   162→}
   163→
   164→/// Summary statistics for a conversation set.
   165→pub struct ConversationStats {
   166→    /// Total conversation count.
   167→    pub total: usize,
   168→    /// Count by protocol.
   169→    pub by_protocol: HashMap<TransportKind, usize>,
   170→    /// Count by state.
   171→    pub by_state: HashMap<ConversationState, usize>,
   172→    /// Count by kind.
   173→    pub by_kind: HashMap<ConversationKind, usize>,
   174→}
   175→
   176→/// Convert a Flow to a Conversation.
   177→pub(crate) fn flow_to_conversation(
   178→    flow: crate::Flow<'_>,
   179→    protocol: TransportKind,
   180→) -> Result<Conversation, CoreError> {
   181→    use crate::conversation::ConversationId;
   182→
   183→    let event_ids: Vec<_> = flow.events.iter().map(|e| e.id).collect();
   184→
   185→    // Compute metrics from events
   186→    let metrics = super::metrics::compute_metrics(&flow.events)?;
   187→
   188→    // Determine conversation kind and state
   189→    let (kind, state) = classify_conversation(&flow.events, protocol, &flow.metadata);
   190→
   191→    // Generate summary
   192→    let summary = generate_summary(&flow.metadata, kind, state, &metrics);
   193→
   194→    let mut conversation = Conversation::new(
   195→        ConversationId::new(flow.id),
   196→        kind,
   197→        protocol,
   198→        state,
   199→    );
   200→
   201→    conversation.event_ids = event_ids;
   202→    conversation.metrics = metrics;
   203→    conversation.metadata = flow.metadata;
   204→    conversation.summary = summary;
   205→
   206→    Ok(conversation)
   207→}
   208→
